package server
var dashboardHTML = []byte(`<!DOCTYPE html><html lang="en"><head><meta charset="UTF-8"><title>Stockyard Windmill — Data Pipeline Visualizer</title><style>*{box-sizing:border-box;margin:0;padding:0}body{font-family:'JetBrains Mono',monospace;background:#1a1008;color:#e8d5b0;min-height:100vh}header{background:#2d1f0e;border-bottom:1px solid #8b6914;padding:1rem 2rem;display:flex;align-items:center;gap:1rem}.logo{font-size:1.4rem;font-weight:700;color:#c9892a}.sub{color:#a07840;font-size:.85rem}.container{max-width:1100px;margin:2rem auto;padding:0 1.5rem}.card{background:#2d1f0e;border:1px solid #4a3520;border-radius:8px;padding:1.5rem;margin-bottom:1.5rem}.card h2{color:#c9892a;font-size:1rem;margin-bottom:1rem}.health{display:inline-block;background:#1a3a1a;color:#4caf50;border:1px solid #4caf50;padding:.2rem .7rem;border-radius:4px;font-size:.8rem}.api-list{list-style:none}.api-list li{padding:.4rem 0;border-bottom:1px solid #3a2a18;font-size:.85rem;color:#c8a96e}.api-list li:last-child{border-bottom:none}</style></head><body><header><div class="logo">Stockyard</div><div class="sub">Visualize job dependencies, see what ran and when.</div></header><div class="container"><div class="card"><h2>Status</h2><span class="health" id="hs">checking...</span></div><div class="card"><h2>Endpoints</h2><ul class="api-list" id="ep"></ul></div></div><script>fetch("/health").then(function(r){return r.json()}).then(function(d){document.getElementById("hs").textContent=d.status==="ok"?"healthy":"degraded"}).catch(function(){var el=document.getElementById("hs");el.textContent="unreachable";el.style.cssText="background:#3a1a1a;color:#f44336;border-color:#f44336"});["GET /api/stats","GET /api/jobs","POST /api/jobs","DELETE /api/jobs/{id}","POST /api/jobs/{id}/runs","GET /api/jobs/{id}/runs"].forEach(function(r){var li=document.createElement("li");li.textContent=r;document.getElementById("ep").appendChild(li)});</script></body></html>`)
